'use client';

import React, { useState } from 'react';
import { Pause, Play, Pencil, Trash2, X, AlertTriangle, Check } from 'lucide-react';
import { Modal } from '@/src/components/ui/Modal';
import { Button } from '@/src/components/ui/Button';
import { cn } from '@/src/lib/utils';
import type { Campaign } from '../types';

interface CampaignActionsMenuProps {
  open: boolean;
  onClose: () => void;
  campaign?: Campaign;
}

type ActionState = 'menu' | 'confirmDelete' | 'done';

export function CampaignActionsMenu({ open, onClose, campaign }: CampaignActionsMenuProps) {
  const [actionState, setActionState] = useState<ActionState>('menu');
  const [doneMessage, setDoneMessage] = useState('');

  const close = () => { setActionState('menu'); onClose(); };

  const handleAction = (action: 'pause' | 'resume' | 'edit') => {
    const msg =
      action === 'pause' ? `"${campaign?.name}" has been paused.` :
      action === 'resume' ? `"${campaign?.name}" is now active.` :
      `Edit mode opened for "${campaign?.name}".`;
    setDoneMessage(msg);
    setActionState('done');
  };

  return (
    <Modal
      open={open}
      onClose={close}
      title={campaign?.name ?? 'Campaign Actions'}
      size="sm"
    >
      {actionState === 'confirmDelete' ? (
        <div className="space-y-4">
          <div className="flex gap-3 p-4 bg-red-50 rounded-xl border border-red-100">
            <AlertTriangle className="w-5 h-5 text-red-500 shrink-0 mt-0.5" />
            <p className="text-xs text-red-700">
              <strong>Delete "{campaign?.name}"?</strong> This will permanently remove the campaign and all its data.
            </p>
          </div>
          <div className="flex gap-2">
            <Button variant="outline" className="flex-1" onClick={() => setActionState('menu')}>← Back</Button>
            <Button variant="danger" className="flex-1" onClick={() => {
              setDoneMessage(`"${campaign?.name}" has been deleted.`);
              setActionState('done');
            }}>
              Delete Campaign
            </Button>
          </div>
        </div>
      ) : actionState === 'done' ? (
        <div className="flex flex-col items-center gap-4 py-2 text-center">
          <div className="w-14 h-14 bg-g-pale rounded-full flex items-center justify-center">
            <Check className="w-7 h-7 text-g-dark" />
          </div>
          <p className="text-sm text-text-mid">{doneMessage}</p>
          <Button className="w-full" onClick={close}>Done</Button>
        </div>
      ) : (
        <div className="space-y-2">
          {/* Status badge */}
          <div className="flex items-center gap-2 p-3 bg-g-faint rounded-xl border border-border-light mb-3">
            <span className={cn(
              'px-2 py-0.5 rounded-full text-[10px] font-bold',
              campaign?.status === 'Active' ? 'bg-g-pale text-g-dark' :
              campaign?.status === 'Paused' ? 'bg-yellow-50 text-yellow-700' : 'bg-gray-100 text-gray-500'
            )}>
              {campaign?.status}
            </span>
            <span className="text-xs text-text-muted">{campaign?.orders} orders · {campaign?.revenue}</span>
          </div>

          {/* Actions */}
          {[
            campaign?.status === 'Active'
              ? { icon: Pause, label: 'Pause Campaign', action: () => handleAction('pause'), cls: 'text-yellow-700 hover:bg-yellow-50' }
              : { icon: Play, label: 'Resume Campaign', action: () => handleAction('resume'), cls: 'text-g-dark hover:bg-g-faint' },
            { icon: Pencil, label: 'Edit Campaign', action: () => handleAction('edit'), cls: 'text-text-mid hover:bg-g-faint' },
            { icon: Trash2, label: 'Delete Campaign', action: () => setActionState('confirmDelete'), cls: 'text-red-500 hover:bg-red-50' },
          ].map(({ icon: Icon, label, action, cls }) => (
            <button
              key={label}
              onClick={action}
              className={cn(
                'w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-semibold transition-all border border-transparent',
                cls
              )}
            >
              <Icon className="w-4 h-4 shrink-0" />
              {label}
            </button>
          ))}

          <div className="pt-1">
            <Button variant="outline" className="w-full" onClick={close}>
              <X className="w-4 h-4" /> Close
            </Button>
          </div>
        </div>
      )}
    </Modal>
  );
}
